    public function index()
    {
        $articles = collect(self::articles())->map(fn ($a) => collect($a)->except('content', 'meta_description')->all())->all();
        return view('blog-index', ['articles' => $articles]);
    }

    public function show(string $slug)
    {
        $articles = self::articles();
        $article = collect($articles)->firstWhere('slug', $slug);
        if (!$article) abort(404);

        $related = collect($articles)
            ->where('slug', '!=', $slug)
            ->map(fn ($a) => collect($a)->except('content', 'meta_description')->all())
            ->values()
            ->all();

        return view('blog-article', ['article' => $article, 'related' => $related]);
    }

    public static function slugs(): array
    {
        return array_column(self::articles(), 'slug');
    }
}
